#include <bits/stdc++.h>
using namespace std;

const int N = 5e4 + 5;
int fa[3 * N], sz[3 * N];

int find(int x)
{
    return fa[x] == x ? x : fa[x] = find(fa[x]);
}

void merge(int x, int y)
{
    x = find(x), y = find(y);
    if (x == y) return;
    if (sz[x] > sz[y]) swap(x, y);
    fa[x] = y;
    sz[y] += sz[x];
}

int main()
{
    int n, m, ans = 0;
    cin >> n >> m;
    for(int i = 1; i <= n * 3 + 1; i++)
        fa[i] = i;
    for(int i = 1; i <= m; i++)
    {
        int z, x, y;
        cin >> z >> x >> y;
        if(z == 1)
        {
            if(x > n || y > n)
                ans++;
            else if(find(x) == find(y + n) || find(x) == find(y + 2 * n))
                ans++;
            else
            {
                merge(x, y);
                merge(x + n, y + n);
                merge(x + 2 * n, y + 2 * n);
            }
        }
        if(z == 2)
        {
            if(x > n || y > n)
                ans++;
            else if(find(x) == find(y))
                ans++;
            else if(find(x) == find(y + n))
                ans++;
            else
            {
                merge(x, y + 2 * n);
                merge(x + n, y);
                merge(x + 2 * n, y + n);
            }
        }
    }
    cout << ans;
    return 0;
}
